// Format the duration column to show calculated calendar days
frappe.listview_settings['Task'].formatters = frappe.listview_settings['Task'].formatters || {};

frappe.listview_settings['Task'].formatters['duration'] = function(value, df, doc) {
    if (!doc.exp_start_date || !doc.exp_end_date) {
        return '<span style="color:#A0AEC0;">—</span>';
    }
    var start = new Date(doc.exp_start_date.split(' ')[0]);
    var end   = new Date(doc.exp_end_date.split(' ')[0]);
    var days  = Math.round((end - start) / 86400000);
    if (days < 0) {
        return '<span style="color:#E53E3E;font-weight:600;">' + days + ' days</span>';
    } else if (days === 0) {
        return '<span style="color:#A0AEC0;">Same day</span>';
    } else {
        return '<span style="color:#2B6CB0;font-weight:600;">' + days + ' day' + (days !== 1 ? 's' : '') + '</span>';
    }
};

