// Parent Task formatter
frappe.listview_settings['Task'].formatters['parent_task'] = function(value, df, doc) {
    if (!value) return '<span style="color:#999;">None</span>';
    if (frappe.boot.parent_task_titles && frappe.boot.parent_task_titles[value]) {
        return frappe.boot.parent_task_titles[value];
    }
    return value;
};

// Duration (Days) — calculated from start/end dates, same day = 1d
frappe.listview_settings['Task'].formatters['duration'] = function(value, df, doc) {
    if (!doc.exp_start_date || !doc.exp_end_date) {
        return '<span style="color:#A0AEC0;">—</span>';
    }
    var start = new Date(doc.exp_start_date.split(' ')[0]);
    var end   = new Date(doc.exp_end_date.split(' ')[0]);
    var days  = Math.floor((end - start) / 86400000) + 1;
    if (days < 1) {
        return '<span style="color:#E53E3E;font-weight:600;">' + days + 'd</span>';
    }
    return '<span style="color:#2B6CB0;font-weight:600;">' + days + 'd</span>';
};

