// Task Visibility Filter
// Non-System-Managers only see tasks they created or are assigned to
frappe.listview_settings['Task'].onload = function(listview) {
    // System Managers see all tasks
    if (frappe.user_roles && frappe.user_roles.includes('System Manager')) {
        return;
    }

    var me = frappe.session.user;

    // Override get_args to inject or_filters
    var original_get_args = listview.get_args;
    listview.get_args = function() {
        var args = original_get_args.call(this);
        // Show tasks where: I am the owner OR I am assigned
        args.or_filters = [
            ['owner', '=', me],
            ['_assign', 'like', '%' + me + '%']
        ];
        return args;
    };

    // Refresh to apply filter
    listview.refresh();
};

frappe.ui.form.on("Timesheet", {
    setup(frm) {
        frm.fields_dict.time_logs.grid.get_field("task").get_query = function(doc, cdt, cdn) {
            let row = locals[cdt][cdn];
            return { filters: { project: row.project || "" } };
        };
    },

    refresh(frm) {
        // Hide parent clutter fields
        ["customer","currency","exchange_rate","sales_invoice","parent_project",
         "total_billable_hours","total_billable_amount","total_costing_amount",
         "base_total_billable_amount","base_total_costing_amount","total_billed_hours",
         "total_billed_amount","base_total_billed_amount","per_billed"
        ].forEach(function(f) { frm.set_df_property(f, "hidden", 1); });

        // Hide child fields in edit popup
        ["from_time","to_time","activity_type","expected_hours",
         "completed","is_billable","billing_hours","billing_rate","billing_amount",
         "base_billing_rate","base_billing_amount","costing_rate","costing_amount",
         "base_costing_rate","base_costing_amount","sales_invoice","description","project_name"
        ].forEach(function(f) {
            frm.fields_dict.time_logs.grid.update_docfield_property(f, "hidden", 1);
        });

        // Inject CSS to hide unwanted grid columns and resize visible ones
        if (!document.getElementById("ts-grid-style")) {
            let style = document.createElement("style");
            style.id = "ts-grid-style";
            style.textContent = [
                '/* Hide Activity Type and Is Billable columns in both header and rows */',
                '.frappe-control[data-fieldname="time_logs"] .col[data-fieldname="activity_type"] { display: none !important; }',
                '.frappe-control[data-fieldname="time_logs"] .col[data-fieldname="is_billable"] { display: none !important; }',
                '/* Resize Project and Hours columns to fill the space */',
                '.frappe-control[data-fieldname="time_logs"] .col[data-fieldname="project"] { flex: 0 0 40% !important; max-width: 40% !important; }',
                '.frappe-control[data-fieldname="time_logs"] .col[data-fieldname="hours"] { flex: 0 0 15% !important; max-width: 15% !important; }',
                '.frappe-control[data-fieldname="time_logs"] .col[data-fieldname="task"] { flex: 0 0 35% !important; max-width: 35% !important; }'
            ].join("\n");
            document.head.appendChild(style);
        }
    },

    before_save(frm) {
        let base_date = frm.doc.start_date || frappe.datetime.get_today();
        let hash = 0;
        let seed = frm.doc.name || String(Date.now());
        for (let i = 0; i < seed.length; i++) {
            hash = ((hash << 5) - hash) + seed.charCodeAt(i);
            hash |= 0;
        }
        let start_min = Math.abs(hash % 1440);
        let h = Math.floor(start_min / 60);
        let m = start_min % 60;
        let current_time = new Date(base_date + " 00:00:00");
        current_time.setHours(h, m, 0, 0);

        (frm.doc.time_logs || []).forEach(function(row) {
            let hrs = row.hours || 1;
            row.from_time = frappe.datetime.get_datetime_as_string(current_time);
            current_time = new Date(current_time.getTime() + (hrs * 60 * 60 * 1000));
            row.to_time = frappe.datetime.get_datetime_as_string(current_time);
            current_time = new Date(current_time.getTime() + 1000);
        });
    }
});

